#!/usr/bin/env node
/**
 * Bundle analysis script for Angular 21 + esbuild.
 * Reads stats.json (generated by `ng build --stats-json`) for module-level detail,
 * or falls back to file sizes when stats.json is absent.
 *
 * Usage:
 *   bun scripts/bundle-report.mjs            → HTML report + console summary
 *   bun scripts/bundle-report.mjs --check    → exit 1 if initial > BUDGET_KB
 *   bun scripts/bundle-report.mjs --json     → print JSON to stdout
 */
import { readdirSync, readFileSync, statSync, writeFileSync, existsSync } from 'fs';
import { join, resolve } from 'path';

const BUDGET_KB = 400;
const DIST_DIR = resolve('dist/educa-angular/browser');
const STATS_PATH = resolve('dist/educa-angular/stats.json');
const REPORT_PATH = resolve('dist/bundle-report.html');

const args = process.argv.slice(2);
const checkMode = args.includes('--check');
const jsonMode = args.includes('--json');

if (!existsSync(DIST_DIR)) {
	console.error('❌ dist/ not found. Run the build first.');
	process.exit(1);
}

// #region Parse stats.json or fall back to file sizes
const hasStats = existsSync(STATS_PATH);
let stats;
if (hasStats) {
	stats = JSON.parse(readFileSync(STATS_PATH, 'utf8'));
}

function groupModule(inputPath) {
	const p = inputPath.replace(/\\/g, '/');
	if (p.includes('node_modules')) {
		const parts = p.split('node_modules/');
		const pkg = parts[parts.length - 1].split('/').slice(0, p.includes('@') ? 2 : 1).join('/');
		return 'node_modules/' + pkg;
	}
	if (p.includes('src/app/')) {
		const parts = p.split('src/app/')[1].split('/');
		return parts[0] === 'features' && parts.length > 2
			? 'src/app/' + parts.slice(0, 3).join('/')
			: 'src/app/' + parts.slice(0, 2).join('/');
	}
	return 'other';
}

const jsFiles = readdirSync(DIST_DIR).filter(f => f.endsWith('.js') && !f.endsWith('.server.js'));
const chunks = [];

for (const file of jsFiles) {
	const filePath = join(DIST_DIR, file);
	const sizeKB = +(statSync(filePath).size / 1024).toFixed(2);
	const sources = {};

	if (hasStats && stats.outputs[file]) {
		const inputs = stats.outputs[file].inputs || {};
		for (const [inputPath, { bytesInOutput }] of Object.entries(inputs)) {
			const mod = groupModule(inputPath);
			sources[mod] = (sources[mod] || 0) + bytesInOutput;
		}
	}

	chunks.push({ file, sizeKB, sources });
}
// #endregion

// #region Classify initial vs lazy
function collectInitialChunks(outputs) {
	const initial = new Set();
	const mainKey = Object.keys(outputs).find(k => /^main(-[^.]+)?\.js$/.test(k));
	if (!mainKey) return initial;
	initial.add(mainKey);
	const polyfillsKey = Object.keys(outputs).find(k => /^polyfills(-[^.]+)?\.js$/.test(k));
	if (polyfillsKey) initial.add(polyfillsKey);

	function walk(key) {
		const entry = outputs[key];
		if (!entry?.imports) return;
		for (const imp of entry.imports) {
			if (imp.kind === 'import-statement' && !initial.has(imp.path)) {
				initial.add(imp.path);
				walk(imp.path);
			}
		}
	}
	walk(mainKey);
	return initial;
}

let initialSet;
if (hasStats) {
	initialSet = collectInitialChunks(stats.outputs);
} else {
	const mainFile = jsFiles.find(f => f === 'main.js' || f.startsWith('main-'));
	initialSet = new Set();
	if (mainFile) {
		initialSet.add(mainFile);
		const mainContent = readFileSync(join(DIST_DIR, mainFile), 'utf8');
		for (const m of mainContent.matchAll(/import\(["']\.\/([^"']+)["']\)/g)) {
			initialSet.add(m[1]);
		}
		const polyfills = jsFiles.find(f => /^polyfills(-[^.]+)?\.js$/.test(f));
		if (polyfills) initialSet.add(polyfills);
	}
}

for (const c of chunks) {
	c.initial = initialSet.has(c.file);
}

const initial = chunks.filter(c => c.initial).sort((a, b) => b.sizeKB - a.sizeKB);
const lazy = chunks.filter(c => !c.initial).sort((a, b) => b.sizeKB - a.sizeKB);
const initialKB = +initial.reduce((s, c) => s + c.sizeKB, 0).toFixed(2);
const lazyKB = +lazy.reduce((s, c) => s + c.sizeKB, 0).toFixed(2);
// #endregion

// #region JSON mode
if (jsonMode) {
	console.log(JSON.stringify({ initialKB, lazyKB, budgetKB: BUDGET_KB, initial, lazy }, null, 2));
	process.exit(0);
}
// #endregion

// #region Console summary
const status = initialKB > BUDGET_KB ? '🔴' : initialKB > BUDGET_KB * 0.9 ? '🟡' : '🟢';
console.log('');
console.log(`  ${status} Initial bundle: ${initialKB} kB (budget: ${BUDGET_KB} kB)`);
console.log(`  📦 Lazy chunks:    ${lazyKB} kB (${lazy.length} chunks)`);
console.log(`  📊 Total app:      ${((initialKB + lazyKB) / 1024).toFixed(2)} MB`);
if (!hasStats) console.log('  ℹ️  No stats.json — run with --stats-json for module breakdown.');
console.log('');

if (initial.length > 0) {
	console.log('  Initial chunks:');
	for (const c of initial) {
		const top = Object.entries(c.sources).sort((a, b) => b[1] - a[1])[0];
		const topLabel = top ? ` ← ${top[0]} (${(top[1] / 1024).toFixed(1)} kB)` : '';
		console.log(`    ${c.sizeKB.toFixed(1).padStart(8)} kB  ${c.file}${topLabel}`);
	}
	console.log('');
}

if (initialKB > BUDGET_KB) {
	console.log(`  ⚠️  Over budget by ${(initialKB - BUDGET_KB).toFixed(1)} kB`);
	console.log('');
}
// #endregion

// #region HTML report
function severity(kb) {
	if (kb > 200) return '#ef4444';
	if (kb > 100) return '#f59e0b';
	if (kb > 50) return '#3b82f6';
	return '#22c55e';
}

function chunkRows(list) {
	return list.map(r => {
		const color = severity(r.sizeKB);
		const srcCount = Object.keys(r.sources).length;
		const topSources = Object.entries(r.sources).sort((a, b) => b[1] - a[1]).slice(0, 5)
			.map(([m, b]) => m.replace('node_modules/', '📦 ').replace('src/app/', '📁 ') + ' (' + (b / 1024).toFixed(1) + ' kB)')
			.join('<br>');
		return `<tr><td><span style="display:inline-block;width:12px;height:12px;border-radius:50%;background:${color}"></span> ${r.file}</td><td style="text-align:right;font-weight:bold">${r.sizeKB.toFixed(1)} kB</td><td>${srcCount}</td><td style="font-size:0.85em">${topSources}</td></tr>`;
	}).join('');
}

const byModule = {};
for (const r of chunks) {
	for (const [mod, bytes] of Object.entries(r.sources)) {
		byModule[mod] = (byModule[mod] || 0) + bytes;
	}
}
const moduleRows = Object.entries(byModule).sort((a, b) => b[1] - a[1]).slice(0, 40).map(([mod, bytes]) => {
	const kb = (bytes / 1024).toFixed(1);
	const inInitial = initial.some(r => r.sources[mod]);
	const badge = inInitial
		? '<span style="background:#ef4444;color:white;padding:1px 6px;border-radius:4px;font-size:0.75em">INITIAL</span>'
		: '<span style="background:#22c55e;color:white;padding:1px 6px;border-radius:4px;font-size:0.75em">LAZY</span>';
	return `<tr><td>${mod} ${badge}</td><td style="text-align:right;font-weight:bold">${kb} kB</td></tr>`;
}).join('');

const budgetBar = `<div style="margin:12px 0;background:#334155;border-radius:8px;height:24px;position:relative;overflow:hidden"><div style="width:${Math.min(100, (initialKB / BUDGET_KB) * 100)}%;height:100%;background:${initialKB > BUDGET_KB ? '#ef4444' : initialKB > BUDGET_KB * 0.9 ? '#f59e0b' : '#22c55e'};border-radius:8px;transition:width 0.3s"></div><span style="position:absolute;right:8px;top:2px;font-size:0.85em">${initialKB.toFixed(0)} / ${BUDGET_KB} kB</span></div>`;

const statsNote = hasStats ? '' : '<p style="color:#f59e0b">⚠️ No stats.json — module breakdown unavailable. Build with <code>--stats-json</code> for full detail.</p>';

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>Bundle Report</title>
<style>body{font-family:system-ui;max-width:1200px;margin:0 auto;padding:20px;background:#0f172a;color:#e2e8f0}h1,h2,h3{color:#f8fafc}table{width:100%;border-collapse:collapse;margin:16px 0}th,td{padding:8px 12px;border:1px solid #334155;text-align:left}th{background:#1e293b}tr:hover{background:#1e293b}.card{background:#1e293b;border-radius:12px;padding:20px;margin:16px 0}.metric{font-size:2em;font-weight:bold}.tabs{display:flex;gap:8px;margin:20px 0}.tab{padding:10px 20px;background:#334155;border:none;color:#e2e8f0;border-radius:8px;cursor:pointer;font-size:1em}.tab.active{background:#3b82f6}.panel{display:none}.panel.active{display:block}.compare{display:flex;gap:20px;flex-wrap:wrap}.compare .card{flex:1;min-width:200px;text-align:center}code{background:#334155;padding:2px 6px;border-radius:4px}</style></head><body>
<h1>Bundle Report</h1>${statsNote}
<h3>Budget</h3>${budgetBar}
<div class="compare">
<div class="card"><div>Initial Bundle</div><div class="metric" style="color:${initialKB > BUDGET_KB ? '#ef4444' : '#22c55e'}">${initialKB.toFixed(0)} kB</div></div>
<div class="card"><div>Lazy Chunks</div><div class="metric">${lazyKB.toFixed(0)} kB</div><div style="color:#94a3b8">${lazy.length} chunks</div></div>
<div class="card"><div>Total</div><div class="metric">${((initialKB + lazyKB) / 1024).toFixed(2)} MB</div></div>
</div>
<div class="tabs"><button class="tab active" onclick="showTab(0)">Initial (${initial.length})</button><button class="tab" onclick="showTab(1)">Lazy (top 30)</button><button class="tab" onclick="showTab(2)">By Module (top 40)</button></div>
<div class="panel active" id="p0"><table><tr><th>Chunk</th><th>Size</th><th>Modules</th><th>Top Sources</th></tr>${chunkRows(initial)}</table></div>
<div class="panel" id="p1"><table><tr><th>Chunk</th><th>Size</th><th>Modules</th><th>Top Sources</th></tr>${chunkRows(lazy.slice(0, 30))}</table></div>
<div class="panel" id="p2"><table><tr><th>Module</th><th>Total Size</th></tr>${moduleRows}</table></div>
<script>function showTab(n){document.querySelectorAll(".panel").forEach((p,i)=>{p.classList.toggle("active",i===n)});document.querySelectorAll(".tab").forEach((t,i)=>{t.classList.toggle("active",i===n)})}</script>
</body></html>`;

writeFileSync(REPORT_PATH, html);
console.log(`  📄 Report: ${REPORT_PATH}`);
// #endregion

// #region Check mode
if (checkMode && initialKB > BUDGET_KB) {
	process.exit(1);
}
// #endregion
